48	pub fn build_glob_set(patterns: &[String]) -> Result<GlobSet, globset::Error> {
49	    let mut builder = GlobSetBuilder::new();
50	    for pat in patterns {
51	        builder.add(Glob::new(pat)?);
52	    }
53	    builder.build()
54	}
