56	pub fn is_rust_file(path: &Path) -> bool {
57	    path.extension().and_then(|e| e.to_str()) == Some("rs")
58	}
59	
60	pub fn should_skip(path: &Path, exclude_set: &GlobSet) -> bool {
61	    if exclude_set.is_empty() {
62	        return false;
63	    }
64	    exclude_set.is_match(path)
65	}
