    fn is_same_location_same_file_same_line_returns_true() {
        let a = FunctionInfo {
            file: "a.rs".to_string(),
            start_line: 5,
            end_line: 10,
            node_hashes: vec![],
        };
        let b = FunctionInfo {
            file: "a.rs".to_string(),
            start_line: 5,
            end_line: 10,
            node_hashes: vec![],
        };
        assert!(is_same_location(&a, &b));
    }

    #[test]
    fn is_same_location_different_file_returns_false() {
        let a = FunctionInfo {
            file: "a.rs".to_string(),
            start_line: 5,
            end_line: 10,
            node_hashes: vec![],
        };
        let b = FunctionInfo {
            file: "b.rs".to_string(),
            start_line: 5,
            end_line: 10,
            node_hashes: vec![],
        };
        assert!(!is_same_location(&a, &b));
    }

    #[test]
    fn find_duplicate_pairs_skips_same_location() {
        let f1 = FunctionInfo {
            file: "a.rs".to_string(),
            start_line: 1,
            end_line: 10,
            node_hashes: vec![1, 2, 3, 4, 5],
        };
        let f2 = FunctionInfo {
            file: "a.rs".to_string(),
            start_line: 1,
            end_line: 10,
            node_hashes: vec![1, 2, 3, 4, 5],
        };
        let pairs = find_duplicate_pairs(&[f1, f2], 0.5, 1, 1);
        assert_eq!(pairs.len(), 0, "same-location pair should be skipped");
    }

    #[test]
    fn execute_cli_invalid_format_returns_exit_2() {
        let result = execute_cli(
            &[".".to_string()],
            "xml",
            None,
            Config::default(),
            |_, _| RunResult::Clean,
        );
        assert_eq!(result.exit_code, 2);
        assert!(result.stderr.contains("error:"));
        assert!(result.stdout.is_empty());
    }

    #[test]
    fn execute_cli_invalid_lang_returns_exit_2() {
        let result = execute_cli(
            &[".".to_string()],
            "text",
            Some("python"),
            Config::default(),
            |_, _| RunResult::Clean,
        );
        assert_eq!(result.exit_code, 2);
        assert!(result.stderr.contains("error:"));
    }

    #[test]
    fn execute_cli_clean_text_returns_exit_0_empty_stdout() {
        let result = execute_cli(
            &[".".to_string()],
            "text",
            None,
            Config::default(),
            |_, _| RunResult::Clean,
        );
        assert_eq!(result.exit_code, 0);
        assert!(result.stdout.is_empty());
        assert!(result.stderr.is_empty());
    }

    #[test]
    fn execute_cli_clean_json_returns_exit_0_empty_array() {
        let result = execute_cli(
            &[".".to_string()],
            "json",
            None,
            Config::default(),
            |_, _| RunResult::Clean,
        );
        assert_eq!(result.exit_code, 0);
        assert_eq!(result.stdout.trim(), "[]");
        assert!(result.stderr.is_empty());
    }

    #[test]
    fn execute_cli_duplicates_returns_exit_1_with_text_output() {
        let pair = DuplicatePair {
            score: 0.9,
            left: PairEndpoint {
                file: "a.rs".to_string(),
                start_line: 1,
                end_line: 5,
                nodes: 10,
            },
            right: PairEndpoint {
                file: "b.rs".to_string(),
                start_line: 1,
                end_line: 5,
                nodes: 10,
            },
        };
        let result = execute_cli(
            &[".".to_string()],
            "text",
            None,
            Config::default(),
            move |_, _| RunResult::Duplicates(vec![pair.clone()]),
        );
        assert_eq!(result.exit_code, 1);
        assert!(result.stdout.contains("DUPLICATE"));
        assert!(result.stderr.is_empty());
    }

    #[test]
    fn execute_cli_duplicates_json_returns_exit_1_with_json_output() {
        let pair = DuplicatePair {
            score: 0.9,
            left: PairEndpoint {
                file: "a.rs".to_string(),
                start_line: 1,
                end_line: 5,
                nodes: 10,
            },
            right: PairEndpoint {
                file: "b.rs".to_string(),
                start_line: 1,
                end_line: 5,
                nodes: 10,
            },
        };
        let result = execute_cli(
            &[".".to_string()],
            "json",
            None,
            Config::default(),
            move |_, _| RunResult::Duplicates(vec![pair.clone()]),
        );
        assert_eq!(result.exit_code, 1);
        assert!(result.stdout.contains("score"));
        assert!(result.stderr.is_empty());
    }

    #[test]
    fn execute_cli_error_returns_exit_2_with_stderr() {
        let result = execute_cli(
            &[".".to_string()],
            "text",
            None,
            Config::default(),
            |_, _| RunResult::Error("something went wrong".to_string()),
        );
        assert_eq!(result.exit_code, 2);
        assert!(result.stderr.contains("error:"));
        assert!(result.stdout.is_empty());
    }

    #[test]
    fn execute_cli_valid_lang_rust_proceeds() {
        let result = execute_cli(
            &[".".to_string()],
            "text",
            Some("rust"),
            Config::default(),
            |_, _| RunResult::Clean,
        );
        assert_eq!(result.exit_code, 0);
    }

    #[test]
    fn make_pair_produces_correct_endpoints() {
        let a = FunctionInfo {
            file: "a.rs".to_string(),
            start_line: 1,
            end_line: 5,
            node_hashes: vec![1, 2],
        };
        let b = FunctionInfo {
            file: "b.rs".to_string(),
            start_line: 1,
            end_line: 5,
            node_hashes: vec![1, 2, 3],
        };
        let pair = make_pair(&a, &b, 0.9);
        assert_eq!(pair.left.file, "a.rs");
        assert_eq!(pair.right.file, "b.rs");
        assert!((pair.score - 0.9).abs() < 1e-9);
    }
}

